//! Minimal Rust code writer for syntaqlite codegen
//!
//! Mirrors `CWriter`'s core pattern: single String buffer with indentation tracking.
//! Use `lines()` for multiline static blocks; use `line()` + `indent()`/`dedent()`
//! for dynamic content in loops.

use super::text_writer::TextWriterCore;

const RUST_FILE_HEADER: &str = "\
// Copyright 2025 The syntaqlite Authors. All rights reserved.
// Licensed under the Apache License, Version 2.0.
//
// @generated by syntaqlite-buildtools — DO NOT EDIT

";

/// Simple Rust code writer with single-buffer output and indentation tracking
pub(crate) struct RustWriter {
    core: TextWriterCore,
}

impl RustWriter {
    // ========== Public API ==========

    pub(crate) fn new() -> Self {
        Self {
            core: TextWriterCore::new(),
        }
    }

    pub(crate) fn finish(self) -> String {
        self.core.finish()
    }

    // Basic output

    pub(crate) fn newline(&mut self) -> &mut Self {
        self.core.newline();
        self
    }

    pub(crate) fn line(&mut self, text: &str) -> &mut Self {
        self.core.line(text);
        self
    }

    /// Emit a block opener and increase indentation.
    ///
    /// Example: `open_block("impl Foo {")`.
    pub(crate) fn open_block(&mut self, header: &str) -> &mut Self {
        self.line(header);
        self.indent()
    }

    /// Decrease indentation and emit a block closer.
    ///
    /// Example: `close_block("}")`.
    pub(crate) fn close_block(&mut self, footer: &str) -> &mut Self {
        self.dedent();
        self.line(footer)
    }

    /// Emit a multiline string block, stripping common leading whitespace.
    ///
    /// Leading/trailing blank lines are trimmed. The minimum indentation across
    /// non-empty lines is stripped, then each line is emitted at the writer's
    /// current indent level. Empty lines become blank lines (no trailing spaces).
    ///
    /// ```ignore
    /// w.lines("
    ///     pub fn foo() {
    ///         body
    ///     }
    /// ");
    /// ```
    pub(crate) fn lines(&mut self, text: &str) -> &mut Self {
        let raw_lines: Vec<&str> = text.lines().collect();

        // Trim leading/trailing empty lines
        let start = raw_lines
            .iter()
            .position(|l| !l.trim().is_empty())
            .unwrap_or(0);
        let end = raw_lines
            .iter()
            .rposition(|l| !l.trim().is_empty())
            .map(|i| i + 1)
            .unwrap_or(0);
        if start >= end {
            return self;
        }
        let lines = &raw_lines[start..end];

        // Find minimum indentation among non-empty lines
        let min_indent = lines
            .iter()
            .filter(|l| !l.trim().is_empty())
            .map(|l| l.len() - l.trim_start().len())
            .min()
            .unwrap_or(0);

        for line in lines {
            if line.trim().is_empty() {
                self.newline();
            } else {
                let stripped = &line[min_indent..];
                self.line(stripped);
            }
        }
        self
    }

    /// Start a block (increase indentation)
    pub(crate) fn indent(&mut self) -> &mut Self {
        self.core.indent();
        self
    }

    /// End a block (decrease indentation)
    pub(crate) fn dedent(&mut self) -> &mut Self {
        self.core.dedent();
        self
    }

    /// Emit the syntaqlite copyright + @generated header.
    pub(crate) fn file_header(&mut self) {
        self.core.push_raw(RUST_FILE_HEADER);
    }

    /// Emit a doc comment line: `/// text` (or just `///` if text is empty)
    pub(crate) fn doc_comment(&mut self, text: &str) -> &mut Self {
        if text.is_empty() {
            self.line("///");
        } else {
            self.line(&format!("/// {}", text));
        }
        self
    }
}

impl Default for RustWriter {
    fn default() -> Self {
        Self::new()
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_lines_strips_common_indent() {
        let mut w = RustWriter::new();
        w.lines(
            "
            pub fn foo() {
                body
            }
        ",
        );
        let output = w.finish();
        assert_eq!(output, "pub fn foo() {\n    body\n}\n");
    }

    #[test]
    fn test_lines_respects_writer_indent() {
        let mut w = RustWriter::new();
        w.indent();
        w.lines(
            "
            fn bar() {
                x
            }
        ",
        );
        let output = w.finish();
        assert_eq!(output, "    fn bar() {\n        x\n    }\n");
    }

    #[test]
    fn test_lines_with_empty_lines() {
        let mut w = RustWriter::new();
        w.lines(
            "
            a

            b
        ",
        );
        let output = w.finish();
        assert_eq!(output, "a\n\nb\n");
    }
}
